function countRangeSum(nums, lower, upper) {
    let sums = new Array(nums.length + 1).fill(0);
    for (let i = 0; i < nums.length; ++i)
        sums[i + 1] = sums[i] + nums[i];

    function mergeSort(start, end) {
        if (start === end)
            return 0;
        let mid = start + Math.floor((end - start) / 2);
        let count = mergeSort(start, mid) + mergeSort(mid + 1, end);

        let j = mid + 1, k = mid + 1;
        for (let i = start; i <= mid; ++i) {
            while (j <= end && sums[j] - sums[i] < lower) ++j;
            while (k <= end && sums[k] - sums[i] <= upper) ++k;
            count += k - j;
        }

        let sortedPart = sums.slice(start, end + 1).sort((a, b) => a - b);
        for (let i = start; i <= end; ++i) {
            sums[i] = sortedPart[i - start];
        }

        return count;
    };

    return mergeSort(0, nums.length);
}
```


    The algorithm is based on the divide-and-conquer strategy. First, we calculate the cumulative sums of the input array. Then, we apply a modified merge-sort function to count the number of range sums that lie in the [lower, upper] interval.

During the merge-sort, for each subarray from index i to mid, we find the first `j` and the first `k` that meet the following conditions:
- `sums[j] - sums[i] >= lower`, and
- `sums[k] - sums[i] > upper`.

The number of range sums in this subarray that lie in the [lower, upper] interval is `k - j`. We add this count to the result.

Finally, we merge the sorted partitions of the subarray.

This process is repeated recursively for all subarrays until only one element remains. At the end, the function should return the total count of range sums that lie in the [lower, upper] interval.

